def gen(rng, size):
    n = max(1, min(size, 500))
    arr = [rng.randint(-1000, 1000)]
    for _ in range(n - 1):
        arr.append(rng.randint(-1000, 1000) if rng.random() < 0.7 else None)
    while arr and arr[-1] is None:
        arr.pop()
    return [arr]

