class Solution:
    def findBottomLeftValue(self, root):
        best_depth = -1
        best_val = root.val
        def dfs(node, depth):
            nonlocal best_depth, best_val
            if node is None:
                return
            if depth > best_depth:
                best_depth = depth
                best_val = node.val
            dfs(node.left, depth + 1)
            dfs(node.right, depth + 1)
        dfs(root, 0)
        return best_val

