class Solution:
    def findBottomLeftValue(self, root):
        from collections import deque
        q = deque([root])
        ans = root.val
        while q:
            ans = q[0].val
            for _ in range(len(q)):
                node = q.popleft()
                if node.left:
                    q.append(node.left)
                if node.right:
                    q.append(node.right)
        return ans

