var findBottomLeftValue = function(root) {
    let q = [root];
    let ans = root.val;
    while (q.length) {
        ans = q[0].val;
        const next = [];
        for (const node of q) {
            if (node.left) next.push(node.left);
            if (node.right) next.push(node.right);
        }
        q = next;
    }
    return ans;
};
